import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { FiMail, FiLock, FiEye, FiEyeOff, FiUser, FiCheck } from 'react-icons/fi';

function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [otpSent, setOtpSent] = useState(false);
  const [otpTimer, setOtpTimer] = useState(15);
  const [resetPassword, setResetPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const { login, loading } = useAuth();
  const navigate = useNavigate();
  const [view, setView] = useState('login');

  useEffect(() => {
    let interval = null;
    if (view === 'forgot' && otpSent && otpTimer > 0) {
      interval = setInterval(() => setOtpTimer(t => t - 1), 1000);
    }
    return () => clearInterval(interval);
  }, [view, otpSent, otpTimer]);

  useEffect(() => {
    if (otpSent && otp[0] === '' && document.getElementById('otp-field-0')) {
      document.getElementById('otp-field-0').focus();
    }
  }, [otpSent]);

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    try {
      await login(email, password);
      navigate('/for-you');
    } catch (err) {
      setError(err.message || 'Failed to log in. Please check your credentials.');
    }
  };

  const handleRegister = (e) => {
    e.preventDefault();
    alert('Registered successfully (placeholder logic)');
    setView('login');
  };

  const handleSendOtp = () => {
    if (!email.trim()) {
      setError('Please enter email');
      return;
    }
    setOtpSent(true);
    setOtpTimer(15);
    setOtp(['', '', '', '', '', '']);
    setError('');
  };

  const handleOtpInput = (e, idx) => {
    let val = e.target.value.replace(/[^0-9]/g, '').slice(0, 1);
    let next = [...otp];
    next[idx] = val;
    setOtp(next);
    setError('');
    if (val && idx < otp.length - 1) {
      document.getElementById(`otp-field-${idx + 1}`).focus();
    }
  };

  const handleOtpPaste = (e) => {
    e.preventDefault();
    let val = e.clipboardData.getData('text').replace(/[^0-9]/g, '').slice(0, 6).split('');
    let nextOtp = otp.map((_, i) => val[i] || '');
    setOtp(nextOtp);
    setError('');
    if (val.length > 0 && val.length <= 6) {
      document.getElementById(`otp-field-${Math.min(val.length - 1, 5)}`).focus();
    }
  };

  const handleReset = (e) => {
    e.preventDefault();
    if (!resetPassword || !confirmPassword) {
      setError('Please fill both fields');
      return;
    }
    if (resetPassword !== confirmPassword) {
      setError('Passwords do not match');
      return;
    }
    setError('');
    setView('changed');
  };

  const goBackToLogin = () => {
    setView('login');
    setError('');
    setOtpSent(false);
    setOtp(['', '', '', '', '', '']);
    setOtpTimer(15);
    setResetPassword('');
    setConfirmPassword('');
    setFullName('');
    setEmail('');
    setPassword('');
    setShowPassword(false);
    setShowConfirmPassword(false);
  };

  const handleNext = () => {
    if (!otpSent) {
      setError('Please send OTP first');
      return;
    }
    const isComplete = otp.every(digit => digit !== '');
    if (!isComplete) {
      setError('Please enter full OTP');
      return;
    }
    setError('');
    setView('reset');
  };

  const styles = {
    loginContainer: {
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      minHeight: '100vh',
      background: '#2196F3',
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", "Roboto", sans-serif',
      position: 'relative',
      overflow: 'hidden',
    },
    backgroundAnimation: {
      position: 'absolute',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      background: `
        radial-gradient(circle at 20% 80%, rgba(120, 119, 198, 0.3) 0%, transparent 50%),
        radial-gradient(circle at 80% 20%, rgba(255, 119, 198, 0.3) 0%, transparent 50%),
        radial-gradient(circle at 40% 40%, rgba(120, 219, 255, 0.2) 0%, transparent 50%)
      `,
    },
    loginCard: {
      display: 'flex',
      backgroundColor: 'rgba(255, 255, 255, 0.95)',
      backdropFilter: 'blur(20px)',
      borderRadius: '24px',
      boxShadow: '0 25px 50px rgba(0, 0, 0, 0.15)',
      overflow: 'hidden',
      width: '1000px',
      maxWidth: '90%',
      minHeight: '600px',
      border: '1px solid rgba(255, 255, 255, 0.2)',
    },
    loginFormSection: {
      flex: 1,
      padding: '50px',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'center',
    },
    graphicSection: {
      flex: 1,
      background: 'linear-gradient(135deg, rgba(102, 126, 234, 0.1) 0%, rgba(118, 75, 162, 0.1) 100%)',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'center',
      alignItems: 'center',
      padding: '40px',
      position: 'relative',
      overflow: 'hidden',
    },
    heading: {
      fontSize: '2.8em',
      color: 'transparent',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      WebkitBackgroundClip: 'text',
      backgroundClip: 'text',
      marginBottom: '40px',
      fontWeight: '700',
      textAlign: 'center',
    },
    whiteHeading: {
      fontSize: '2.8em',
      color: 'white',
      marginBottom: '40px',
      fontWeight: '700',
      textAlign: 'center',
    },
    form: {
      width: '100%',
      display: 'flex',
      flexDirection: 'column',
      gap: '24px',
    },
    inputGroup: { position: 'relative' },
    input: {
      padding: '18px 20px 18px 60px',
      border: '2px solid rgba(226, 232, 240, 0.8)',
      borderRadius: '16px',
      fontSize: '1em',
      width: '100%',
      boxSizing: 'border-box',
      transition: 'all 0.3s ease',
      backgroundColor: 'rgba(248, 250, 252, 0.8)',
      fontWeight: '500',
