    otpContainer: {
      display: 'flex',
      justifyContent: 'center',
      gap: '10px',
      margin: '20px 0',
    },
    otpInput: {
      width: 50,
      height: 50,
      textAlign: 'center',
      borderRadius: 8,
      border: otpSent ? '2px solid #4e54c8' : '1px solid #ccc',
      fontSize: '1.5em',
      backgroundColor: 'white',
      outline: 'none',
    },
    timerText: {
      textAlign: 'center',
      color: '#888',
      margin: '10px 0',
    },
    resendButton: {
      color: '#667eea',
      fontWeight: '600',
      fontSize: '1.05em',
      cursor: 'pointer',
      transition: 'color 0.2s',
      border: 'none',
      background: 'none',
      textAlign: 'center',
      width: '100%',
    },
  };

  const userIcon = { icon: '👤' };
  const animationStyles = `
    @keyframes float {
      0%, 100% { transform: translateY(0px) rotate(0deg); }
      50% { transform: translateY(-20px) rotate(180deg); }
    }
  `;

  const isOtpComplete = otp.every(digit => digit !== '');

  return (
    <>
      <style>{animationStyles}</style>
      <div style={styles.loginContainer}>
        <div style={styles.backgroundAnimation} />
        {view === 'changed' && (
          <div style={styles.successCard}>
            <h2 style={styles.whiteHeading}>FLOW TRACK</h2>
            <FiCheck style={styles.checkIcon} />
            <div style={styles.successMessage}>Password Changed Successfully</div>
            <button style={styles.blueButton} onClick={goBackToLogin}>Back to Login</button>
            <div style={styles.footer}>©2025 Viranchi Technologies Pvt Ltd</div>
          </div>
        )}
        {view === 'forgot' && (
          <div style={styles.simpleCard}>
            <h2 style={styles.heading}>FLOW TRACK</h2>
            <label style={styles.labelStyle}>Email Address</label>
            <input
              type="email"
              placeholder="Email Address"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              style={styles.simpleInput}
            />
            <button 
              style={styles.button} 
              disabled={!email.trim()} 
              onClick={handleSendOtp}
            >
              Send OTP
            </button>
            <label style={styles.labelStyle}>OTP</label>
            <div style={styles.otpContainer}>
              {otp.map((digit, idx) => (
                <input
                  key={idx}
                  id={`otp-field-${idx}`}
                  type="text"
                  value={digit}
                  onChange={(e) => handleOtpInput(e, idx)}
                  onPaste={handleOtpPaste}
                  maxLength={1}
                  style={styles.otpInput}
                  disabled={!otpSent}
                  autoFocus={idx === 0 && otpSent}
                />
              ))}
            </div>
            {otpSent && (
              otpTimer > 0 ? (
                <div style={styles.timerText}>{otpTimer}s left</div>
              ) : (
                <button style={styles.resendButton} onClick={handleSendOtp}>
                  Resend OTP
                </button>
              )
            )}
            <button 
              style={styles.button} 
              disabled={!otpSent || !isOtpComplete}
              onClick={handleNext}
            >
              Next
            </button>
            <button style={styles.grayButton} onClick={goBackToLogin}>
              Back to Login
            </button>
            {error && <p style={styles.errorMessage}>{error}</p>}
          </div>
        )}
        {view === 'reset' && (
          <div style={styles.simpleCard}>
            <h2 style={styles.heading}>FLOW TRACK</h2>
            <form onSubmit={handleReset}>
              <label style={styles.labelStyle}>New Password</label>
              <div style={styles.inputGroup}>
                <FiLock style={styles.inputIcon} />
                <input
                  type={showPassword ? 'text' : 'password'}
                  placeholder="New Password"
                  value={resetPassword}
                  onChange={(e) => setResetPassword(e.target.value)}
                  required
                  style={styles.input}
                />
                {showPassword ? (
                  <FiEyeOff style={styles.eyeIcon} onClick={() => setShowPassword(false)} />
                ) : (
                  <FiEye style={styles.eyeIcon} onClick={() => setShowPassword(true)} />
                )}
              </div>
              <label style={styles.labelStyle}>Confirm Password</label>
              <div style={styles.inputGroup}>
                <FiLock style={styles.inputIcon} />
                <input
                  type={showConfirmPassword ? 'text' : 'password'}
                  placeholder="Confirm Password"
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  required
                  style={styles.input}
                />
                {showConfirmPassword ? (
                  <FiEyeOff style={styles.eyeIcon} onClick={() => setShowConfirmPassword(false)} />
                ) : (
                  <FiEye style={styles.eyeIcon} onClick={() => setShowConfirmPassword(true)} />
                )}
              </div>
              <button type="submit" style={styles.button}>Change Password</button>
              <button type="button" style={styles.grayButton} onClick={goBackToLogin}>
                Back to Login
              </button>
            </form>
            {error && <p style={styles.errorMessage}>{error}</p>}
          </div>
        )}
        {view === 'register' && (
          <div style={styles.simpleCard}>
            <h2 style={styles.heading}>FLOW TRACK</h2>
            <form onSubmit={handleRegister}>
              <label style={styles.labelStyle}>Full Name</label>
              <div style={styles.inputGroup}>
                <FiUser style={styles.inputIcon} />
                <input
                  type="text"
                  placeholder="Full Name"
                  value={fullName}
                  onChange={(e) => setFullName(e.target.value)}
                  required
                  style={styles.input}
                />
              </div>
              <label style={styles.labelStyle}>Email Address</label>
              <div style={styles.inputGroup}>
                <FiMail style={styles.inputIcon} />
                <input
                  type="email"
                  placeholder="Email Address"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  style={styles.input}
                />
              </div>
              <label style={styles.labelStyle}>Password</label>
              <div style={styles.inputGroup}>
                <FiLock style={styles.inputIcon} />
                <input
                  type={showPassword ? 'text' : 'password'}
                  placeholder="Password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                  style={styles.input}
                />
                {showPassword ? (
                  <FiEyeOff style={styles.eyeIcon} onClick={() => setShowPassword(false)} />
                ) : (
                  <FiEye style={styles.eyeIcon} onClick={() => setShowPassword(true)} />
                )}
              </div>
              <button type="submit" style={styles.button}>Register</button>
              <button type="button" style={styles.grayButton} onClick={goBackToLogin}>
                Back to Login
              </button>
            </form>
          </div>
        )}
        {view === 'login' && (
          <div style={styles.loginCard}>
            <div style={styles.loginFormSection}>
              <h2 style={styles.heading}>FLOW TRACK</h2>
              <form onSubmit={handleLogin} style={styles.form}>
                <div style={styles.inputGroup}>
                  <FiMail style={styles.inputIcon} />
                  <input
                    type="email"
                    placeholder="Email Address"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    required
                    style={styles.input}
                  />
                </div>
                <div style={styles.inputGroup}>
                  <FiLock style={styles.inputIcon} />
                  <input
                    type={showPassword ? 'text' : 'password'}
                    placeholder="Password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    required
                    style={styles.input}
                  />
                  {showPassword ? (
                    <FiEyeOff style={styles.eyeIcon} onClick={() => setShowPassword(false)} />
                  ) : (
                    <FiEye style={styles.eyeIcon} onClick={() => setShowPassword(true)} />
                  )}
                </div>
                <button type="submit" style={styles.button} disabled={loading}>
                  {loading ? 'Signing In...' : 'Sign In'}
                </button>
                {error && <p style={styles.errorMessage}>{error}</p>}
              </form>
              <div style={{ marginTop: 30, textAlign: 'center', display: 'flex', justifyContent: 'center', gap: 30 }}>
                <span style={styles.bottomText} onClick={() => setView('forgot')}>Forgot Password?</span>
                <span style={styles.bottomText} onClick={() => setView('register')}>Registration</span>
              </div>
            </div>
            <div style={styles.graphicSection}>
              <div style={{ fontSize: '80px', color: '#667eea' }}>{userIcon.icon}</div>
              <h3 style={{ color: '#2D3748' }}>Welcome Back</h3>
              <p style={{ color: '#4A5568', textAlign: 'center' }}>
                Sign in to access your projects, collaborate with your team,
                and continue tracking your progress seamlessly.
              </p>
            </div>
          </div>
        )}
      </div>
    </>
  );
}

export default Login;
